test_cases.python_test_script:
def test_tc_wip_008_no_invalid_values(can_bus):
    msgs = collect_bcm_messages(can_bus, 2.0)
    for m in msgs:
        assert get_wiper_speed(m.data) in (0, 1, 2, 3)

def test_tc_wip_009_periodic_rate(can_bus):
    msgs = collect_bcm_messages(can_bus, 1.0)
    assert len(msgs) >= MIN_PERIODIC_FRAMES_PER_SEC

def test_tc_wip_010_no_errors(can_bus):
    msgs = collect_bcm_messages(can_bus, 2.0)
    for m in msgs:
        assert not m.is_error_frame
